import functools

class Solution:
    def minDeletion(self, nums):
        n = len(nums)
        INF = float('inf')

        @functools.lru_cache(maxsize=None)
        def best(i, parity, last):
            if i == n:
                return 0 if parity == 0 else INF
            skip = 1 + best(i + 1, parity, last)
            if parity == 0:
                keep = best(i + 1, 1, nums[i])
            else:
                keep = best(i + 1, 0, -1) if nums[i] != last else INF
            return min(skip, keep)

        result = best(0, 0, -1)
        best.cache_clear()
        return result

