class Solution:
    def minDeletion(self, nums):
        deletions = 0
        kept_len = 0
        last = None
        for x in nums:
            if kept_len % 2 == 0:
                last = x
                kept_len += 1
            else:
                if x == last:
                    deletions += 1
                else:
                    kept_len += 1
        if kept_len % 2 == 1:
            deletions += 1
        return deletions

